import fs from 'fs';

import { GatlingAssertion, getGatlingStatus } from '.';
import { TestSimulation, TestSimulationStep } from '../model';

import { getGatlingSimulation, getGatlingReportUrl, getTestPlanFile, getXrayDefaultTestPlanKey } from '../config';

export function getReportDescription(): string {
  let description = `Test execution generated by xray-connector for Test Plan ${getXrayDefaultTestPlanKey()}`;

  if (getGatlingSimulation()) {
    description += '\n\n';
    description += getGatlingStatus()
      .assertions.map(
        (assertion: GatlingAssertion) => `Assert ${assertion.message} - ` + (assertion.status ? 'PASS' : 'FAIL'),
      )
      .join('\n');
  }

  if (getGatlingReportUrl()) {
    description += '\n\n';
    description += 'Please refer to Gatling report for details :\n';
    description += getGatlingReportUrl();
  }

  if (getTestPlanFile()) {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any,@typescript-eslint/no-unsafe-assignment
    const testPlan: any = JSON.parse(fs.readFileSync(getTestPlanFile(), 'utf8'));
    // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
    const simulations: TestSimulation[] = (testPlan['simulations'] as TestSimulation[]) || [];

    description += '\n\n';
    description += simulations
      .map((simulation: TestSimulation, index: number) => {
        let simulationInfo = '';
        simulationInfo += `---- Simulation ${index} ---\n`;
        simulationInfo += `Tag : ${simulation.tag}\n`;
        simulationInfo += simulation.injectionSteps.map((step: TestSimulationStep) => {
          let simulationStepInfo = '';
          simulationStepInfo += `Injection Profile : ${step.injectionProfile}\n`;
          simulationStepInfo += `Nb users : ${step.users}\n`;
          simulationStepInfo += `Duration : ${step.duration}\n`;
          return simulationStepInfo;
        });
        return simulationInfo;
      })
      .join('\n\n');
  }

  return description;
}
